import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface VideoAsset {
  id: string;
  title: string;
  duration: string;
  resolution: string;
  fps: number;
  format: string;
  thumbnail: string;
  tags: string[];
  dateAdded: string;
  folderId: string;
}

export interface Directory {
  id: string;
  name: string;
  type: 'local' | 'external' | 'cloud' | 'smart';
  path: string;
  icon?: React.ReactNode;
  children?: Directory[];
  status?: 'idle' | 'indexing' | 'offline';
  itemCount?: number;
}

export type ViewMode = 'grid' | 'list';

import React from 'react';

export const WindowControls: React.FC = () => {
  return (
    <div className="flex gap-2 p-4 group">
      <div className="w-3 h-3 rounded-full bg-red-500 hover:bg-red-600 transition-colors shadow-sm" />
      <div className="w-3 h-3 rounded-full bg-yellow-400 hover:bg-yellow-500 transition-colors shadow-sm" />
      <div className="w-3 h-3 rounded-full bg-green-500 hover:bg-green-600 transition-colors shadow-sm" />
    </div>
