import React, { useState } from 'react';
import { 
  HardDrive, 
  Folder, 
  Plus, 
  Loader2, 
  Sparkles, 
  LayoutGrid, 
  Clock, 
  ChevronRight, 
  ChevronDown 
} from 'lucide-react';
import { Directory } from '../types';
import { WindowControls } from './WindowControls';

interface SidebarProps {
  directories: Directory[];
  activeId: string | null;
  onSelect: (id: string) => void;
  onMountDrive: () => void;
}

const DirectoryItem: React.FC<{ 
  dir: Directory; 
  depth?: number; 
  activeId: string | null; 
  onSelect: (id: string) => void 
}> = ({ dir, depth = 0, activeId, onSelect }) => {
  const [expanded, setExpanded] = useState(false);
  const isActive = activeId === dir.id;
  const hasChildren = dir.children && dir.children.length > 0;

  const getIcon = () => {
    if (dir.type === 'smart') return <Sparkles size={16} className="text-purple-500" />;
    if (dir.type === 'external') return <HardDrive size={16} className="text-orange-500" />;
    return <Folder size={16} className="text-blue-500" />;
  };

  return (
    <div>
      <div 
        onClick={() => {
            onSelect(dir.id);
            if (hasChildren) setExpanded(!expanded);
        }}
        className={`
          group flex items-center justify-between py-1.5 px-2 rounded-lg text-sm cursor-pointer select-none transition-all duration-200
          ${isActive ? 'bg-white/10 text-white font-medium shadow-sm backdrop-blur-sm' : 'text-gray-400 hover:bg-white/5 hover:text-gray-200'}
        `}
        style={{ paddingLeft: `${depth * 16 + 12}px` }}
      >
        <div className="flex items-center gap-2.5 overflow-hidden">
            <span className="opacity-70 group-hover:opacity-100 transition-opacity">
                 {hasChildren ? (
                    expanded ? <ChevronDown size={12} /> : <ChevronRight size={12} />
                 ) : (
                     <div className="w-3" />
                 )}
            </span>
            {getIcon()}
            <span className="truncate">{dir.name}</span>
        </div>

        {dir.status === 'indexing' && (
          <Loader2 size={12} className="animate-spin text-blue-400" />
        )}
        {dir.status !== 'indexing' && dir.itemCount && (
            <span className={`text-[10px] ${isActive ? 'text-white/60' : 'text-gray-600'}`}>
                {dir.itemCount}
            </span>
        )}
      </div>

      {hasChildren && expanded && (
        <div className="flex flex-col">
          {dir.children?.map(child => (
            <DirectoryItem 
                key={child.id} 
                dir={child} 
                depth={depth + 1} 
                activeId={activeId} 
                onSelect={onSelect} 
            />
          ))}
        </div>
      )}
    </div>
  );
};

export const Sidebar: React.FC<SidebarProps> = ({ directories, activeId, onSelect, onMountDrive }) => {
  const smartDirs = directories.filter(d => d.type === 'smart');
  const driveDirs = directories.filter(d => d.type !== 'smart');

  return (
    <div className="w-[280px] h-full flex flex-col bg-[#1E1E1E]/95 backdrop-blur-2xl border-r border-white/5">
      <WindowControls />

      <div className="flex-1 overflow-y-auto px-3 py-2 space-y-6">
        {/* Smart Collections */}
        <div>
            <h3 className="text-[11px] font-semibold text-gray-500 uppercase tracking-wider mb-2 px-3">
                Library
            </h3>
            <div className="space-y-0.5">
                 <div 
                    onClick={() => onSelect('all')}
                    className={`
                      flex items-center gap-3 py-1.5 px-3 rounded-lg text-sm cursor-pointer transition-colors
                      ${activeId === 'all' ? 'bg-white/10 text-white' : 'text-gray-400 hover:bg-white/5 hover:text-gray-200'}
                    `}
                >
                    <LayoutGrid size={16} className="text-gray-400" />
                    All Assets
                </div>
                {smartDirs.map(dir => (
                    <DirectoryItem key={dir.id} dir={dir} activeId={activeId} onSelect={onSelect} />
                ))}
            </div>
        </div>

        {/* Drives & Locations */}
        <div>
             <div className="flex items-center justify-between px-3 mb-2">
                <h3 className="text-[11px] font-semibold text-gray-500 uppercase tracking-wider">
                    Locations
                </h3>
                <button 
                    onClick={onMountDrive}
                    className="p-1 hover:bg-white/10 rounded-md text-gray-500 hover:text-white transition-colors"
                    title="Mount New Drive"
                >
                    <Plus size={12} />
                </button>
            </div>

            <div className="space-y-0.5">
                {driveDirs.map(dir => (
                    <DirectoryItem key={dir.id} dir={dir} activeId={activeId} onSelect={onSelect} />
                ))}
            </div>
        </div>
      </div>

      {/* Footer / Status */}
      <div className="p-4 border-t border-white/5 bg-black/20">
        <div className="flex items-center gap-3">
            <div className="relative">
                <div className="w-8 h-8 rounded-full bg-gradient-to-tr from-blue-500 to-purple-500 flex items-center justify-center text-xs font-bold text-white">
                    AI
                </div>
                <div className="absolute bottom-0 right-0 w-2.5 h-2.5 bg-green-500 border-2 border-[#1E1E1E] rounded-full"></div>
            </div>
            <div className="flex flex-col">
                <span className="text-xs font-medium text-gray-200">Neural Engine</span>
                <span className="text-[10px] text-gray-500">Ready to search</span>
            </div>
        </div>
      </div>
    </div>
  );
};

import React from 'react';
import { Search, Mic, Command } from 'lucide-react';

