import React, { useState, useMemo } from 'react';
import { Sidebar } from './components/Sidebar';
import { SearchBar } from './components/SearchBar';
import { VideoGrid } from './components/VideoGrid';
import { MOCK_DIRECTORIES, MOCK_VIDEOS } from './constants';
import { Directory } from './types';
import { SlidersHorizontal, Settings, UploadCloud } from 'lucide-react';

const App: React.FC = () => {
  const [activeFolderId, setActiveFolderId] = useState<string | null>('all');
  const [searchQuery, setSearchQuery] = useState('');
  const [directories, setDirectories] = useState<Directory[]>(MOCK_DIRECTORIES);

  // Simulate mounting a new drive
  const handleMountDrive = () => {
    const newDrive: Directory = {
      id: `ext-${Date.now()}`,
      name: 'Untitled SSD',
      type: 'external',
      path: '/Volumes/Untitled',
      status: 'indexing',
      itemCount: 0,
      children: []
    };

    setDirectories(prev => [...prev, newDrive]);

    // Simulate indexing finish after 3 seconds
    setTimeout(() => {
        setDirectories(prev => prev.map(d => 
            d.id === newDrive.id 
                ? { ...d, status: 'idle', itemCount: 42, name: 'LUMIX SSD' } 
                : d
        ));
    }, 3000);
  };

  const filteredVideos = useMemo(() => {
    let result = MOCK_VIDEOS;

    // Filter by Folder
    if (activeFolderId && activeFolderId !== 'all') {
       // A simplistic check: matches folderID directly or is in a child folder (simplified for prototype)
       // In a real app, we'd traverse the tree. Here we just match the flat mock data structure.
       // Or if it's a smart folder.
       if (activeFolderId.startsWith('smart-')) {
          // Just randomize/mock smart folder behavior by showing all for now, or specific ones
          if (activeFolderId === 'smart-1') {
              // Recent: just show first 3
              result = result.slice(0, 3);
          }
       } else {
           // Normal folder filtering
           // Check if video belongs to this folder or any parent drive (simplified: just match mock folderId)
           result = result.filter(v => v.folderId === activeFolderId || directories.find(d => d.id === activeFolderId)?.children?.some(c => c.id === v.folderId));
       }
    }

    // Filter by Search Query
    if (searchQuery) {
        const lowerQ = searchQuery.toLowerCase();
        result = result.filter(v => 
            v.title.toLowerCase().includes(lowerQ) || 
            v.tags.some(t => t.toLowerCase().includes(lowerQ))
        );
    }

    return result;
  }, [activeFolderId, searchQuery, directories]);

  return (
    <div className="flex h-screen w-full bg-[#121212] text-white overflow-hidden font-sans selection:bg-blue-500/30">
      <Sidebar 
        directories={directories} 
        activeId={activeFolderId} 
        onSelect={setActiveFolderId}
        onMountDrive={handleMountDrive}
      />

      <main className="flex-1 flex flex-col min-w-0 relative">
        {/* Background Ambient Glow */}
        <div className="absolute top-0 left-0 right-0 h-96 bg-gradient-to-b from-blue-900/10 to-transparent pointer-events-none" />

        {/* Header / Search Area */}
        <header className="flex-shrink-0 px-8 pt-8 pb-4 flex flex-col gap-6 z-10">
          <div className="flex items-center justify-between">
            <h1 className="text-2xl font-semibold tracking-tight text-white/90">
                {activeFolderId === 'all' ? 'All Assets' : 
                 activeFolderId?.startsWith('smart') ? directories.find(d => d.id === activeFolderId)?.name :
                 'Drive Content'}
            </h1>
            <div className="flex items-center gap-3">
                 <button className="p-2 rounded-full hover:bg-white/10 text-gray-400 hover:text-white transition-colors">
                    <UploadCloud size={18} />
                 </button>
                 <button className="p-2 rounded-full hover:bg-white/10 text-gray-400 hover:text-white transition-colors">
                    <SlidersHorizontal size={18} />
                 </button>
                 <button className="p-2 rounded-full hover:bg-white/10 text-gray-400 hover:text-white transition-colors">
                    <Settings size={18} />
                 </button>
            </div>
          </div>

          <div className="flex justify-center w-full">
            <SearchBar value={searchQuery} onChange={setSearchQuery} />
          </div>
        </header>

        {/* Content Area */}
        <div className="flex-1 overflow-y-auto custom-scrollbar">
            <VideoGrid videos={filteredVideos} />
        </div>

        {/* Floating Status Bar (Bottom Right) - Optional macOS aesthetic */}
        <div className="absolute bottom-6 right-6 px-4 py-2 bg-black/40 backdrop-blur-xl border border-white/10 rounded-full text-xs text-gray-400 font-medium shadow-2xl pointer-events-none">
            {filteredVideos.length} items • 12.4 GB available
        </div>
      </main>
    </div>
  );
};

export default App;

