  const totalItems = directories.reduce((acc, curr) => acc + (curr.itemCount || 0), 0);

  return (
    <div className="w-[260px] h-full flex flex-col bg-[#111] border-r border-white/5 select-none pt-2">
      <WindowControls />

      <div className="flex-1 overflow-y-auto py-2 space-y-6 custom-scrollbar">

