};

import React from 'react';
import { Play, FileType, CloudOff, Loader2, Folder } from 'lucide-react';
import { FileSystemItem } from '../types';

interface VideoGridProps {
  items: FileSystemItem[];
  isOfflineView?: boolean;
  onNavigate: (folderId: string, folderName: string) => void;
}

export const VideoGrid: React.FC<VideoGridProps> = ({ items, isOfflineView = false, onNavigate }) => {
  if (items.length === 0) {
    return (
      <div className="flex-1 flex flex-col items-center justify-center text-gray-500 h-full">
        <div className="w-16 h-16 rounded-2xl bg-white/5 flex items-center justify-center mb-4 border border-white/5">
            <FileType className="w-8 h-8 opacity-40" />
        </div>
        <p className="text-sm font-medium text-gray-400">No content</p>
        <p className="text-xs text-gray-600 mt-1">Empty folder or pending index.</p>
      </div>
    );
  }

  return (
    <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 2xl:grid-cols-6 gap-6 p-8 pb-32">
      {items.map((item) => {

        // --- RENDER FOLDER ---
        if (item.type === 'folder') {
            return (
                <div 
                    key={item.id}
                    onClick={() => onNavigate(item.id, item.title)}
                    className={`
                        group relative flex flex-col gap-2 cursor-pointer select-none
                        ${isOfflineView ? 'opacity-60' : ''}
                    `}
                >
                    <div className="relative aspect-[4/3] rounded-xl bg-gradient-to-br from-blue-500/10 to-blue-600/5 border border-blue-500/10 hover:border-blue-400/30 hover:bg-blue-500/20 transition-all duration-200 flex flex-col items-center justify-center shadow-lg group-hover:shadow-blue-900/10">
                        <Folder 
                            size={48} 
                            strokeWidth={1}
                            className="text-blue-400/80 fill-blue-500/10 group-hover:scale-105 transition-transform duration-300" 
                        />
                        <span className="absolute bottom-3 text-[10px] font-medium text-blue-300/60 uppercase tracking-widest">
                            {item.itemCount} items
                        </span>
                    </div>
                    <div className="px-1 text-center">
                        <h4 className="text-xs font-medium text-blue-100/80 truncate group-hover:text-blue-300 transition-colors">
                            {item.title}
                        </h4>
                    </div>
                </div>
            );
        }

        // --- RENDER VIDEO ---
        const isProcessing = item.analysisStatus === 'processing' || item.analysisStatus === 'pending';
        return (
          <div 
            key={item.id} 
            className={`
                group relative flex flex-col gap-2 cursor-pointer
                ${isOfflineView ? 'opacity-60 grayscale-[0.8]' : ''}
            `}
          >
            {/* Thumbnail Container */}
            <div className="relative aspect-video rounded-lg overflow-hidden bg-[#1A1A1A] shadow-lg border border-white/5 transition-all duration-300 group-hover:border-white/20 group-hover:shadow-xl">
              <img 
                src={item.thumbnail} 
                alt={item.title}
                className={`
                    w-full h-full object-cover transition-transform duration-500 group-hover:scale-105
                    ${isProcessing ? 'opacity-50 blur-sm' : ''}
                `}
                loading="lazy"
              />

              {/* Processing Overlay */}
              {isProcessing && (
                  <div className="absolute inset-0 flex flex-col items-center justify-center gap-2">
                      <Loader2 size={20} className="animate-spin text-blue-400" />
                      <span className="text-[9px] font-medium text-blue-300 uppercase tracking-wider">Analyzing</span>
                  </div>
              )}

              {/* Offline Overlay */}
              {isOfflineView && !isProcessing && (
                 <div className="absolute inset-0 flex items-center justify-center bg-black/40 backdrop-blur-[1px]">
                     <CloudOff size={24} className="text-white/50" />
                 </div>
              )}

              {/* Hover Play Button (Only if Online) */}
              {!isOfflineView && !isProcessing && (
                <div className="absolute inset-0 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity duration-200 bg-black/20">
                    <div className="w-8 h-8 rounded-full bg-white/10 backdrop-blur-md flex items-center justify-center border border-white/20 shadow-lg transform scale-90 group-hover:scale-100 transition-transform">
                        <Play size={14} fill="white" className="text-white ml-0.5" />
                    </div>
                </div>
              )}

              {/* Duration Badge */}
              <div className="absolute bottom-1.5 right-1.5 px-1 py-0.5 rounded bg-black/70 backdrop-blur-sm border border-white/5 text-[9px] font-medium text-white/90 font-mono tracking-tight flex items-center gap-1">
                {item.duration}
              </div>
            </div>

            {/* Metadata */}
            <div className="flex flex-col px-0.5 gap-0.5">
              <h4 className={`text-xs font-medium truncate transition-colors ${isOfflineView ? 'text-gray-500' : 'text-gray-300 group-hover:text-white'}`}>
                  {item.title}
              </h4>
              <div className="flex items-center justify-between text-[10px] text-gray-600">
                  <span className="uppercase">{item.resolution}</span>
                  <span>{item.dateAdded}</span>
              </div>
            </div>
          </div>
        );
      })}
    </div>
  );
};

import React, { useState, useMemo, useEffect } from 'react';
import { Sidebar } from './components/Sidebar';
import { SearchBar } from './components/SearchBar';
import { VideoGrid } from './components/VideoGrid';
import { MOCK_DIRECTORIES, MOCK_VIDEOS, MOCK_FOLDERS } from './constants';
import { Directory, FileSystemItem, FolderAsset, VideoAsset } from './types';
import { SlidersHorizontal, AlertTriangle, ChevronRight, Home } from 'lucide-react';

// Breadcrumb Item Type
interface BreadcrumbItem {
  id: string;
  name: string;
}

const App: React.FC = () => {
  // Navigation State
  const [activeRootId, setActiveRootId] = useState<string>('smart-1'); // The Drive/Smart Folder
  const [navigationPath, setNavigationPath] = useState<BreadcrumbItem[]>([]); // Stack for sub-folders

  const [searchQuery, setSearchQuery] = useState('');
  const [directories, setDirectories] = useState<Directory[]>(MOCK_DIRECTORIES);

  // Reset navigation path when clicking a new Sidebar root
  const handleSidebarSelect = (id: string) => {
      setActiveRootId(id);
      setNavigationPath([]); // Reset deep path
  };

  // Handle Drilling Down
  const handleNavigateFolder = (folderId: string, folderName: string) => {
      setNavigationPath(prev => [...prev, { id: folderId, name: folderName }]);
  };

  // Handle Clicking Breadcrumb
  const handleBreadcrumbClick = (index: number) => {
      // Keep everything up to index (0 means just root, empty path)
      // Actually if index is -1 (Root), clear path.
      // If index is 0 (First folder), keep first folder.
      setNavigationPath(prev => prev.slice(0, index + 1));
  };

  // Determine Offline Status
  const isOfflineView = useMemo(() => {
    if (activeRootId.startsWith('smart')) return false;
    const rootDir = directories.find(d => d.id === activeRootId);
    return rootDir ? !rootDir.isConnected : false;
  }, [activeRootId, directories]);

  // Compute Current View Items
  const currentViewItems = useMemo<FileSystemItem[]>(() => {
    // 1. Determine current context ID (either last breadcrumb or root)
    const currentContextId = navigationPath.length > 0 
        ? navigationPath[navigationPath.length - 1].id 
        : activeRootId;

    // 2. If searching, ignore folders and flatten all videos (Global Search context)
    if (searchQuery) {
        const lowerQ = searchQuery.toLowerCase();
        // Search across EVERYTHING in the mock DB for now, or scope to Root if needed
        return MOCK_VIDEOS.filter(v => 
            v.title.toLowerCase().includes(lowerQ) || 
            v.tags.some(t => t.toLowerCase().includes(lowerQ))
        );
    }

    // 3. Normal Navigation: Get items belonging to currentContextId
    let items: FileSystemItem[] = [];

    // 3a. Smart Folder logic (Flattened view of videos)
    if (activeRootId === 'smart-1' && navigationPath.length === 0) {
        return MOCK_VIDEOS;
    }

    // 3b. Find folders inside current context
    const foldersInContext = MOCK_FOLDERS.filter(f => f.folderId === currentContextId);

    // 3c. Find videos inside current context
    const videosInContext = MOCK_VIDEOS.filter(v => v.folderId === currentContextId);

    return [...foldersInContext, ...videosInContext];

  }, [activeRootId, navigationPath, searchQuery, directories]);

  const handleMountDrive = () => {
    const newDrive: Directory = {
      id: `ext-${Date.now()}`,
      name: 'Untitled SSD',
      type: 'external',
      path: '/Volumes/Untitled',
      status: 'indexing',
      indexingProgress: 0,
      isConnected: true,
      itemCount: 0
    };
    setDirectories(prev => [...prev, newDrive]);
    // Simulation logic omitted for brevity, similar to previous
  };

  const handleToggleConnection = (id: string) => {
    setDirectories(prev => prev.map(dir => 
        dir.id === id ? { ...dir, isConnected: !dir.isConnected, status: !dir.isConnected ? 'idle' : 'offline' } : dir
    ));
  };

  // Helper to get Root Name
  const rootName = useMemo(() => {
      return directories.find(d => d.id === activeRootId)?.name || 'Library';
  }, [activeRootId, directories]);

  return (
    <div className="flex h-screen w-full bg-[#050505] text-white overflow-hidden font-sans selection:bg-blue-500/30">
      <Sidebar 
        directories={directories} 
        activeId={activeRootId} 
        onSelect={handleSidebarSelect}
        onMountDrive={handleMountDrive}
        onToggleConnection={handleToggleConnection}
      />

      <main className="flex-1 flex flex-col min-w-0 relative">
        <div className="absolute top-0 left-0 right-0 h-64 bg-gradient-to-b from-[#111] to-transparent pointer-events-none" />

        {/* Header */}
        <header className="flex-shrink-0 px-8 pt-6 pb-2 flex flex-col gap-4 z-10">
          <div className="flex items-center justify-between">
            <div className="flex flex-col gap-1">

                 {/* Breadcrumbs Component */}
                 <nav className="flex items-center text-sm font-medium text-gray-400 select-none">
                    {/* Root Item */}
                    <button 
                        onClick={() => setNavigationPath([])}
                        className={`flex items-center hover:text-white transition-colors ${navigationPath.length === 0 ? 'text-white' : ''}`}
                    >
                        {activeRootId.startsWith('smart') ? <SparklesIcon /> : <Home size={14} className="mr-1.5" />}
                        {rootName}
                    </button>

                    {/* Path Items */}
                    {navigationPath.map((item, index) => (
                        <div key={item.id} className="flex items-center">
                            <ChevronRight size={12} className="mx-2 text-gray-600" />
                            <button 
                                onClick={() => handleBreadcrumbClick(index)}
                                className={`hover:text-white transition-colors ${index === navigationPath.length - 1 ? 'text-white' : ''}`}
                            >
                                {item.name}
                            </button>
                        </div>
                    ))}
                 </nav>

                 {/* Status Badges */}
                 <div className="flex items-center gap-2 mt-1">
                    {isOfflineView && (
                        <span className="text-[10px] text-yellow-500 font-medium uppercase tracking-wide flex items-center gap-1.5 opacity-80">
                            <AlertTriangle size={10} />
                            Source Disconnected
                        </span>
                    )}
                 </div>
            </div>

            <div className="flex items-center gap-2">
                 <button className="w-8 h-8 flex items-center justify-center rounded-lg hover:bg-white/5 text-gray-500 hover:text-white transition-colors">
                    <SlidersHorizontal size={16} />
                 </button>
            </div>
          </div>

          <div className="flex justify-center w-full mt-2">
            <SearchBar value={searchQuery} onChange={setSearchQuery} />
          </div>
        </header>

        {/* Content Area */}
        <div className="flex-1 overflow-y-auto custom-scrollbar">
            <VideoGrid 
                items={currentViewItems} 
                isOfflineView={isOfflineView} 
                onNavigate={handleNavigateFolder}
            />
        </div>

        {/* Footer Info */}
        <div className="absolute bottom-6 right-6 px-4 py-2 bg-[#1A1A1A]/90 backdrop-blur-xl border border-white/5 rounded-full text-xs text-gray-400 font-medium shadow-2xl pointer-events-none flex items-center gap-3">
             <span>{currentViewItems.length} Items</span>
             <span className="w-px h-3 bg-white/10" />
             <span className={isOfflineView ? 'text-yellow-600' : 'text-green-600'}>
                 {isOfflineView ? 'Preview Unavailable' : 'Ready'}
             </span>
        </div>
      </main>
    </div>
  );
};

const SparklesIcon = () => (
    <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" className="mr-1.5 text-purple-400">
        <path d="m12 3-1.912 5.813a2 2 0 0 1-1.275 1.275L3 12l5.813 1.912a2 2 0 0 1 1.275 1.275L12 21l1.912-5.813a2 2 0 0 1 1.275-1.275L21 12l-5.813-1.912a2 2 0 0 1-1.275-1.275L12 3Z"/>
    </svg>
)

export default App;
